    public static void main(String[] args) {
        Animal meuCachorro = new Cachorro("Rex");
        Animal meuGato = new Gato("Mimi");

        // Polimorfismo: ambos são do tipo Animal, mas fazem sons diferentes
        meuCachorro.fazerSom(); // Rex diz: Au Au!
        meuGato.fazerSom();     // Mimi diz: Miau!

        // Podemos criar um array de animais
        Animal[] animais = {meuCachorro, meuGato};

        System.out.println("\nTodos os animais fazem som:");
        for (Animal animal : animais) {
            animal.fazerSom();
        }
    }
}
