### **Classe Principal (Roboheranca) com Lista de Veículos**

```java
import java.util.ArrayList;

public class Roboheranca {
    public static void main(String[] args) {
        ArrayList<Veiculo> listaVeiculos = new ArrayList<>();

        listaVeiculos.add(new Carro("Honda", "Fit", 4));
        listaVeiculos.add(new Moto("Honda", "XV", 90));
        listaVeiculos.add(new Carro("Toyota", "Corolla", 4));
        listaVeiculos.add(new Moto("Yamaha", "Fazer", 250));

        // Exibir informações de todos os veículos
        System.out.println("=== Informações dos veículos ===");
        for (Veiculo v : listaVeiculos) {
            v.exibirInformacoes();
            System.out.println();
        }

        // Exibir o número de portas apenas dos carros
        System.out.println("=== Número de portas dos carros ===");
        for (Veiculo v : listaVeiculos) {
            if (v instanceof Carro) {
                Carro c = (Carro) v; // Downcast para acessar métodos de Carro
                System.out.println(c.getMarca() + " " + c.getModelo() + ": " + c.getNumeroPortas() + " portas");
            }
        }

        // Exibir as cilindradas apenas das motos
        System.out.println("=== Cilindradas das motos ===");
        for (Veiculo v : listaVeiculos) {
            if (v instanceof Moto) {
                Moto m = (Moto) v; // Downcast para acessar métodos de Moto
                System.out.println(m.getMarca() + " " + m.getModelo() + ": " + m.getCilindradas() + " cilindradas");
            }
        }
    }
}
```

